import Foundation

let emptyPath = IndexPath()
print(emptyPath.isEmpty)
let singlePath = IndexPath(index: 1)
print(singlePath.count)
var path = IndexPath(indexes: [2, 4])
print(path.count)
print(path.isEmpty)
path.append(6)
print(path.count)
let longer = path.appending(8)
print(longer.count)
print(path.count)

let emptySet = IndexSet()
print(emptySet.isEmpty)
print(emptySet.first == nil)
let singleSet = IndexSet(integer: 9)
print(singleSet.count)
let closedSet = IndexSet(integersIn: 3 ... 5)
print(closedSet.count)
print(closedSet.last)
var set = IndexSet(integersIn: 3 ..< 6)
print(set.count)
print(set.contains(4))
print(set.contains(8))
print(set.first)
print(set.last)
let inserted = set.insert(8)
print(inserted.inserted)
print(inserted.memberAfterInsert)
print(set.count)
let duplicate = set.insert(8)
print(duplicate.inserted)
print(duplicate.memberAfterInsert)
print(set.count)

// IndexPath subscript, bounds, dropLast, Comparable
var deep = IndexPath(indexes: [1, 2, 3])
print(deep[0], deep[2])
print(deep.startIndex, deep.endIndex)
print(deep.dropLast().count)
print(deep.dropLast(2).count)
print(IndexPath(indexes: [1, 2]) < IndexPath(indexes: [1, 3]))
print(IndexPath(indexes: [1, 2]) <= IndexPath(indexes: [1, 2]))
print(IndexPath(indexes: [2]) > IndexPath(indexes: [1, 9]))

// IndexSet set algebra and queries
var lhs = IndexSet(integersIn: 1 ... 4)
let rhs = IndexSet(integersIn: 3 ... 6)
print(lhs.union(rhs).count)
print(lhs.intersection(rhs).count)
print(lhs.symmetricDifference(rhs).count)
print(lhs.remove(2) ?? -1)
print(lhs.remove(99) ?? -1)
print(lhs.count)
lhs.formUnion(rhs)
print(lhs.count)
lhs.formIntersection(rhs)
print(lhs.count)
lhs.removeAll()
print(lhs.isEmpty)
var q = IndexSet(integersIn: 1 ... 5)
print(q.integerGreaterThan(3) ?? -1)
print(q.integerLessThan(3) ?? -1)
print(q.integerGreaterThanOrEqualTo(3) ?? -1)
print(q.integerLessThanOrEqualTo(3) ?? -1)
print(q.update(with: 3) ?? -1)
print(q.update(with: 9) ?? -1)

// Hashable consistency.
print(IndexPath(indexes: [2, 4]).hashValue == IndexPath(indexes: [2, 4]).hashValue)
print(IndexPath(indexes: [2, 4]).hashValue == IndexPath(indexes: [2, 5]).hashValue)
print(IndexSet(integer: 9).hashValue == IndexSet(integer: 9).hashValue)
